// Telegram message handler
const msg = $input.item.json;

const chatId = msg.message?.chat?.id;
const text = msg.message?.text || '';
const username = msg.message?.chat?.username || 'anonymous';
const firstName = msg.message?.chat?.first_name || 'Friend';

// Route commands
let reply = '';
if (text.startsWith('/start')) {
  reply = `👋 Hey ${firstName}! I'm your AI assistant.\n\nTry asking me anything, or use:\n/start - see this message\n/help - get help\n/status - your session info`;
} else if (text.startsWith('/help')) {
  reply = '📖 Just send me any question or task.\n\nCommands:\n/start - Restart\n/help - This guide\n/status - Session info\n/reset - Clear history';
} else if (text.startsWith('/status')) {
  reply = `📊 Status OK!\nUser: @${username}\nChat ID: ${chatId}\nMode: AI-powered\nContext: Active`;
} else if (text.startsWith('/reset')) {
  reply = '🧹 Memory cleared! Starting fresh. Hi there!';
} else {
  // AI response path (set AI node after this)
  reply = `[AI_RESPONSE_PLACEHOLDER] ${text}`;
}

return [{ json: { chatId, reply, username, firstName } }];
